remotion_integration_notes:
CRITICAL: Leaflet CANNOT use React rendering directly. You MUST use imperative DOM manipulation.

PATTERN:
```tsx
const MapScene: React.FC = () => {
  const frame = useCurrentFrame();
  const ref = useRef<HTMLDivElement>(null);
  const mapRef = useRef<L.Map | null>(null);

  useEffect(() => {
    if (!ref.current || mapRef.current) return;
    const map = L.map(ref.current, {
      zoomControl: false,
      attributionControl: false,
      dragging: false,
      scrollWheelZoom: false,
    });
    L.tileLayer('https://tile.openstreetmap.org/{z}/{x}/{y}.png').addTo(map);
    map.setView([51.505, -0.09], 13);
    mapRef.current = map;
    return () => { map.remove(); mapRef.current = null; };
  }, []);

  useEffect(() => {
    if (!mapRef.current) return;
    const lat = interpolate(frame, [0, 90], [51.505, 48.856]);
    const lng = interpolate(frame, [0, 90], [-0.09, 2.352]);
    const zoom = interpolate(frame, [0, 90], [13, 5]);
    mapRef.current.setView([lat, lng], zoom, { animate: false });
  }, [frame]);

  return <div ref={ref} style={{ width: 1920, height: 1080 }} />;
};
```
